import React, { useState, useEffect } from 'react';
import { BrowserRouter, Routes, Route, Navigate, Link } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { useDropzone } from 'react-dropzone';
import { supabase } from './supabaseClient';
import './App.css';

// ==================== ANIMATIONS ====================
const fadeIn = { initial: { opacity: 0, y: 20 }, animate: { opacity: 1, y: 0 }, transition: { duration: 0.6 } };
const stagger = { initial: {}, animate: { transition: { staggerChildren: 0.1 } } };

// ==================== LOGIN COMPONENT ====================
function Login({ onLogin }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) setError(error.message);
    else onLogin(data.user);
    setLoading(false);
  };

  return (
    <motion.div className="auth-container" {...fadeIn}>
      <div className="auth-card">
        <div className="auth-header">
          <div className="coat-of-arms"></div>
          <h1>République Démocratique du Congo</h1>
          <h2>Plateforme de Réforme Constitutionnelle</h2>
          <p className="subtitle">Participez à l'avenir de notre nation</p>
        </div>
        {error && <div className="error-message">{error}</div>}
        <form onSubmit={handleSubmit}>
          <div className="input-group">
            <label>Adresse Email</label>
            <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} required />
          </div>
          <div className="input-group">
            <label>Mot de Passe</label>
            <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} required />
          </div>
          <button type="submit" disabled={loading} className="btn-primary btn-full">
            {loading ? 'Connexion...' : 'Se Connecter'}
          </button>
        </form>
        <p className="auth-footer">
          Pas encore de compte ? <Link to="/signup">Créer un compte</Link>
        </p>
      </div>
    </motion.div>
  );
}

// ==================== SIGNUP COMPONENT ====================
function Signup({ onSignup }) {
  const [formData, setFormData] = useState({ email: '', password: '', fullName: '', province: '', phone: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const provinces = ['Kinshasa', 'Kongo Central', 'Haut-Katanga', 'Lualaba', 'Nord-Kivu', 'Sud-Kivu', 'Ituri', 'Equateur', 'Mongala', 'Nord-Ubangi', 'Sud-Ubangi', 'Tshopo', 'Bas-Uele', 'Haut-Uele', 'Mai-Ndombe', 'Kwilu', 'Kwango', 'Kasaï', 'Kasaï-Central', 'Kasaï-Oriental', 'Lomami', 'Sankuru', 'Maniema', 'Tanganyika', 'Haut-Lomami'];

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const { data, error } = await supabase.auth.signUp({
      email: formData.email,
      password: formData.password,
      options: { data: { full_name: formData.fullName, province: formData.province, phone: formData.phone } }
    });
    if (error) setError(error.message);
    else if (data.user) {
      await supabase.from('profiles').insert([{
        id: data.user.id,
        email: formData.email,
        full_name: formData.fullName,
        province: formData.province,
        phone: formData.phone,
        role: 'citizen'
      }]);
      onSignup(data.user);
    }
    setLoading(false);
  };

  return (
    <motion.div className="auth-container" {...fadeIn}>
      <div className="auth-card">
        <div className="auth-header">
          <h2>Créer un Compte</h2>
          <p>Inscrivez-vous pour soumettre votre proposition</p>
        </div>
        {error && <div className="error-message">{error}</div>}
        <form onSubmit={handleSubmit}>
          <div className="input-group">
            <label>Nom Complet</label>
            <input type="text" value={formData.fullName} onChange={(e) => setFormData({ ...formData, fullName: e.target.value })} required />
          </div>
          <div className="input-group">
            <label>Email</label>
            <input type="email" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} required />
          </div>
          <div className="input-group">
            <label>Téléphone</label>
            <input type="tel" value={formData.phone} onChange={(e) => setFormData({ ...formData, phone: e.target.value })} />
          </div>
          <div className="input-group">
            <label>Province</label>
            <select value={formData.province} onChange={(e) => setFormData({ ...formData, province: e.target.value })} required>
              <option value="">Sélectionnez votre province</option>
              {provinces.map(p => <option key={p} value={p}>{p}</option>)}
            </select>
          </div>
          <div className="input-group">
            <label>Mot de Passe (min. 6 caractères)</label>
            <input type="password" value={formData.password} onChange={(e) => setFormData({ ...formData, password: e.target.value })} required />
          </div>
          <button type="submit" disabled={loading} className="btn-primary btn-full">{loading ? 'Inscription...' : 'S\'inscrire'}</button>
        </form>
        <p className="auth-footer">Déjà inscrit ? <Link to="/login">Se connecter</Link></p>
      </div>
    </motion.div>
  );
}

// ==================== HOMEPAGE WITH HERO GALLERY ====================
function Homepage({ user }) {
  const images = [
    { src: '/images/gallery/forest-bassin-congo-fr.jpg', title: 'Bassin du Congo', desc: 'Patrimoine mondial' },
    { src: '/images/gallery/okapi-espece-protegee-fr.jpg', title: 'Okapi', desc: 'Espèce protégée' },
    { src: '/images/gallery/gorille-montagne-virunga-fr.jpg', title: 'Gorille des Montagnes', desc: 'Virunga' },
    { src: '/images/gallery/volcan-nyiragongo-goma-fr.jpg', title: 'Nyiragongo', desc: 'Patrimoine naturel' },
    { src: '/images/gallery/fleuve-congo-kinshasa-fr.jpg', title: 'Fleuve Congo', desc: 'Artère vitale' },
    { src: '/images/gallery/president-tshisekedi-rdc-fr.jpg', title: 'Félix Tshisekedi', desc: 'Président de la République' },
  ];

  return (
    <motion.div className="homepage" {...fadeIn}>
      {/* Hero Section */}
      <section className="hero">
        <div className="hero-content">
          <div className="presidential-seal"></div>
          <h1>Réforme Constitutionnelle</h1>
          <h2>Consultation Nationale</h2>
          <p>Contribuez à l'avenir de la République Démocratique du Congo</p>
          {user ? (
            <Link to="/dashboard" className="btn-primary btn-large">Soumettre une Proposition</Link>
          ) : (
            <Link to="/login" className="btn-primary btn-large">Participer Maintenant</Link>
          )}
        </div>
      </section>

      {/* Gallery Section */}
      <section className="gallery-section">
        <div className="container">
          <div className="section-header">
            <h3>Notre Patrimoine</h3>
            <p>La richesse naturelle et culturelle de la RDC</p>
          </div>
          <motion.div className="image-grid" variants={stagger} initial="initial" animate="animate">
            {images.map((img, idx) => (
              <motion.div key={idx} className="gallery-card" variants={fadeIn}>
                <div className="card-image">
                  <img src={img.src} alt={img.title} />
                  <div className="card-overlay">
                    <h4>{img.title}</h4>
                    <p>{img.desc}</p>
                  </div>
                </div>
              </motion.div>
            ))}
          </motion.div>
        </div>
      </section>
    </motion.div>
  );
}

// ==================== DASHBOARD – PROPOSAL SUBMISSION ====================
function Dashboard({ user }) {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [files, setFiles] = useState([]);
  const [loading, setLoading] = useState(false);
  const [proposals, setProposals] = useState([]);
  const [message, setMessage] = useState('');
  const [submitting, setSubmitting] = useState(false);

  const { getRootProps, getInputProps } = useDropzone({
    onDrop: acceptedFiles => setFiles(acceptedFiles),
    accept: { 'image/*': [] },
    maxFiles: 5
  });

  useEffect(() => { fetchProposals(); }, []);

  const fetchProposals = async () => {
    const { data } = await supabase.from('proposals').select('*').order('created_at', { ascending: false }).limit(10);
    if (data) setProposals(data);
  };

  const uploadImages = async () => {
    const urls = [];
    for (const file of files) {
      const fileName = `${Date.now()}-${file.name}`;
      const { error } = await supabase.storage.from('proposal-images').upload(fileName, file);
      if (!error) {
        const { data: { publicUrl } } = supabase.storage.from('proposal-images').getPublicUrl(fileName);
        urls.push(publicUrl);
      }
    }
    return urls;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    setMessage('');
    const imageUrls = await uploadImages();
    const { error } = await supabase.from('proposals').insert([{
      user_id: user.id,
      title,
      content,
      image_urls: imageUrls,
      status: 'pending'
    }]);
    if (error) setMessage('Erreur: ' + error.message);
    else {
      setMessage('Proposition soumise avec succès !');
      setTitle('');
      setContent('');
      setFiles([]);
      fetchProposals();
    }
    setSubmitting(false);
  };

  return (
    <motion.div className="dashboard" {...fadeIn}>
      <div className="dashboard-container">
        {/* Submission Form */}
        <div className="proposal-form-card">
          <div className="card-header">
            <h2>Soumettre une Proposition</h2>
            <p>Partagez votre vision pour la réforme constitutionnelle</p>
          </div>
          {message && <div className="success-message">{message}</div>}
          <form onSubmit={handleSubmit}>
            <div className="input-group">
              <label>Titre de la Proposition</label>
              <input type="text" value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Ex: Réforme du mandat présidentiel" required />
            </div>
            <div className="input-group">
              <label>Contenu détaillé</label>
              <textarea rows="8" value={content} onChange={(e) => setContent(e.target.value)} placeholder="Décrivez votre proposition en détail..." required />
            </div>
            <div className="input-group">
              <label>Documents joints (images)</label>
              <div {...getRootProps()} className="dropzone">
                <input {...getInputProps()} />
                <p>Glissez vos images ici ou cliquez pour sélectionner</p>
                <small>JPG, PNG jusqu'à 5 fichiers</small>
              </div>
              {files.length > 0 && <div className="file-list">{files.map(f => <span key={f.name}>{f.name}</span>)}</div>}
            </div>
            <button type="submit" disabled={submitting} className="btn-primary btn-full">
              {submitting ? 'Soumission...' : 'Soumettre la Proposition'}
            </button>
          </form>
        </div>

        {/* Recent Proposals Feed */}
        <div className="proposals-feed">
          <div className="card-header">
            <h3>Propositions Récentes</h3>
            <p>Découvrez les idées des citoyens</p>
          </div>
          <div className="proposals-list">
            {proposals.map(p => (
              <motion.div key={p.id} className="proposal-item" variants={fadeIn}>
                <div className="proposal-header">
                  <div className="proposal-icon">📄</div>
                  <div>
                    <h4>{p.title}</h4>
                    <small>{new Date(p.created_at).toLocaleDateString('fr-FR')}</small>
                  </div>
                </div>
                <p className="proposal-excerpt">{p.content.substring(0, 150)}...</p>
                {p.image_urls && p.image_urls[0] && <img src={p.image_urls[0]} alt="Aperçu" className="proposal-thumb" />}
              </motion.div>
            ))}
          </div>
        </div>
      </div>
    </motion.div>
  );
}

// ==================== MAIN APP ====================
function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user || null);
      setLoading(false);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user || null);
    });
    return () => subscription.unsubscribe();
  }, []);

  if (loading) return <div className="loading-screen"><div className="loader"></div><p>Chargement...</p></div>;

  return (
    <BrowserRouter>
      <nav className="navbar">
        <div className="nav-container">
          <Link to="/" className="nav-brand">
            <span className="brand-icon">🇨🇩</span>
            <span>RDC | Réforme Constitutionnelle</span>
          </Link>
          <div className="nav-links">
            <Link to="/">Accueil</Link>
            {user && <Link to="/dashboard">Soumettre</Link>}
            {user ? (
              <button onClick={() => supabase.auth.signOut()} className="nav-btn">Déconnexion</button>
            ) : (
              <Link to="/login" className="nav-btn-primary">Connexion</Link>
            )}
          </div>
        </div>
      </nav>
      <Routes>
        <Route path="/" element={<Homepage user={user} />} />
        <Route path="/login" element={user ? <Navigate to="/dashboard" /> : <Login onLogin={setUser} />} />
        <Route path="/signup" element={user ? <Navigate to="/dashboard" /> : <Signup onSignup={setUser} />} />
        <Route path="/dashboard" element={user ? <Dashboard user={user} /> : <Navigate to="/login" />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
